import React, { useEffect, useState } from 'react';
import './App.css';
import { Element, scroller } from 'react-scroll';
import About from './components/about';
import Home from './components/home';
import Navbar from './components/navbar';
import Services from './components/services';
import Contact from './components/contact';
import Footers from './components/footer';
import ScrollToTopArrow from './components/scrolltoparrow';


function App() {
  const [visibleSection, setVisibleSection] = useState('');

  const handleSetActive = (to) => {
    setVisibleSection(to);
  };

  const scrollToSection = (section) => {
    scroller.scrollTo(section, {
      duration: 800,
      delay: 0,
      smooth: 'easeInOutQuart',
    });
  };

  useEffect(() => {
    
    const handleScroll = () => {
      const scrollPosition = window.scrollY;
      const sections = ['home', 'about', 'services', 'contact'];
      const sectionOffsets = {};
    
      // Obtém as posições de início e fim de cada seção
      sections.forEach((section) => {
        const element = document.querySelector(`[name=${section}]`);
        if (element) {
          const offsetTop = element.offsetTop;
          const offsetBottom = offsetTop + element.clientHeight;
          sectionOffsets[section] = { offsetTop, offsetBottom };
        }
      });
    
      // Determina qual seção está atualmente visível
      let currentSection = '';
      for (const section in sectionOffsets) {
        const { offsetTop, offsetBottom } = sectionOffsets[section];
        if (scrollPosition >= offsetTop && scrollPosition < offsetBottom) {
          currentSection = section;
          break;
        }
      }
    
      // Atualiza a seção visível
      handleSetActive(currentSection);
    };

    window.addEventListener('scroll', handleScroll);

    return () => {
      window.removeEventListener('scroll', handleScroll);
    };
  }, []);



  return (
    <div>
      <Navbar scrollToSection={scrollToSection} />
      <Element name="home" className={`section ${visibleSection === 'home' ? 'visible' : ''}`}>
        <Home />
      </Element>
      <Element name="about" className={`section ${visibleSection === 'about' ? 'visible' : ''}`}>
        <About />
      </Element>
      <Element name="services" className={`section ${visibleSection === 'services' ? 'visible' : ''}`}>
        <Services />
      </Element>
      <Element name="contact" className={`section ${visibleSection === 'contact' ? 'visible' : ''}`}>
        <Contact />
      </Element>
      <Footers />
      <ScrollToTopArrow />
    </div>
  );
}

export default App;
